// --- Filet de sécurité anti-page-blanche ------------------------------------------------
// Doit être la toute première chose exécutée dans ce fichier : si n'importe quelle erreur
// survient plus loin (même très tôt, avant que le reste du code ne soit prêt), ceci affiche
// le message d'erreur réel directement dans la page via une bannière rouge, plutôt que de
// laisser un plateau vide sans aucune explication. Ne dépend d'aucune autre variable du
// fichier (ni `els`, ni `state`) pour rester fonctionnel même si l'erreur survient avant
// leur définition.
(function () {
  function showFatalError(err) {
    try {
      var message = (err && err.message) ? err.message : String(err);
      var banner = document.createElement("div");
      banner.textContent = "Erreur au chargement du jeu : " + message + " (merci de signaler ce message exact)";
      banner.style.cssText =
        "position:fixed;top:0;left:0;right:0;z-index:999999;background:#b00020;color:#fff;" +
        "padding:10px 16px;font:14px/1.5 -apple-system,Segoe UI,Helvetica,Arial,sans-serif;" +
        "box-shadow:0 2px 8px rgba(0,0,0,.3);";
      var attach = function () { if (document.body) document.body.prepend(banner); };
      if (document.body) attach();
      else document.addEventListener("DOMContentLoaded", attach);
    } catch (bannerError) {
      // Dernier recours : si même l'affichage de la bannière échoue, on ne peut rien faire
      // de plus côté page ; l'erreur reste au moins visible dans la console.
    }
  }
  window.addEventListener("error", function (event) { showFatalError(event.error || event.message); });
  window.addEventListener("unhandledrejection", function (event) { showFatalError(event.reason); });
})();
