function emptyState() {
  return {
    status: "SETUP",
    mode: "local",
    players: [],
    pieces: [],
    turnOrder: [],
    currentTurnIndex: 0,
    selectedPieceId: null,
    legalDestinations: [],
    moveHistory: [],
    blockedInCycle: new Set(),
    ranking: [],
    winner: null,
    gameStartTime: null,
    aiPreview: null,
    aiPlans: {},
    aiRotationCursor: {},
    victoryPause: false,
    victoryPauseTimeout: null,
    tournament: null,
  };
}

// --- Persistance locale : survit à un rafraîchissement de page (F5) --------------------
// Une partie locale n'existe qu'en mémoire JS ; sans ceci, tout rafraîchissement la
// perdait entièrement. On sauvegarde l'état après chaque rendu tant qu'une partie est en
// cours, et on le restaure au chargement de la page.
const LOCAL_SAVE_KEY = "versoRectoV53Save";

function serializeState(s) {
  return JSON.stringify({
    ...s,
    blockedInCycle: Array.from(s.blockedInCycle || []),
    // États transitoires : n'ont plus de sens après un rechargement (timeouts invalidés,
    // animations en cours), on les remet à leur valeur neutre plutôt que de les stocker.
    aiPreview: null,
    victoryPause: false,
    victoryPauseTimeout: null,
  });
}

function saveGameToStorage() {
  try {
    if (state.status === "PLAYING") {
      localStorage.setItem(LOCAL_SAVE_KEY, serializeState(state));
    } else {
      localStorage.removeItem(LOCAL_SAVE_KEY);
    }
  } catch (error) {
    // Stockage indisponible (navigation privée, quota dépassé, etc.) : on continue sans
    // sauvegarde plutôt que de casser la partie en cours.
  }
}

function clearSavedGame() {
  try { localStorage.removeItem(LOCAL_SAVE_KEY); } catch (error) { /* ignoré */ }
}

function loadGameFromStorage() {
  try {
    const raw = localStorage.getItem(LOCAL_SAVE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (parsed.status !== "PLAYING") return null;
    if (!Array.isArray(parsed.players) || !parsed.players.length) return null;
    if (!Array.isArray(parsed.pieces) || !parsed.pieces.length) return null;
    return {
      ...parsed,
      blockedInCycle: new Set(parsed.blockedInCycle || []),
      selectedPieceId: null,
      legalDestinations: [],
      aiPreview: null,
      victoryPause: false,
      victoryPauseTimeout: null,
    };
  } catch (error) {
    return null;
  }
}

function parseMoveTable(text) {
  const map = {};
  text.trim().split(/\n+/).forEach(line => {
    const [src, dests] = line.split("→").map(s => s.trim());
    if (!src || !dests) return;
    map[src] = [...new Set(dests.split(",").map(s => s.trim()))];
  });
  return map;
}

function shuffle(array) {
  const copy = [...array];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}

function escapeHtml(value) {
  return String(value ?? "").replace(/[&<>"']/g, (char) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#39;",
  }[char]));
}

function sanitizePlayerName(value) {
  return String(value ?? "")
    // supprime les caractères de contrôle éventuels sans dépendre du flag /u (compatibilité large)
    .split("").filter(ch => ch.charCodeAt(0) >= 32).join("")
    .trim()
    .slice(0, 24);
}

function colorDot(colorKey) {
  return `<span class="dot" style="background:${COLORS[colorKey].css}"></span>`;
}

function medalDot(rankIndex) {
  const medal = MEDALS[rankIndex];
  if (!medal) return "";
  return `<span class="medal-chip ${rankIndex === 0 ? "medal-gold" : rankIndex === 1 ? "medal-silver" : "medal-bronze"}"></span>`;
}

function placeLabel(index) {
  if (index === 0) return "1er";
  if (index === 1) return "2e";
  if (index === 2) return "3e";
  return `${index + 1}e`;
}

function renderPlayerInputs() {
  const mode = els.gameMode?.value || "local";

  // Le mode tournoi impose exactement 4 joueurs (une couleur chacun) : le nombre de
  // participants n'est pas configurable dans ce mode.
  if (mode === "tournament") {
    els.playerCount.value = "4";
    els.playerCount.disabled = true;
  } else {
    els.playerCount.disabled = false;
  }
  if (els.tournamentHelp) els.tournamentHelp.hidden = mode !== "tournament";

  const count = Number(els.playerCount.value);
  const allowsPerPlayerType = mode === "mixed" || mode === "tournament";

  els.playerInputs.innerHTML = "";

  for (let i = 0; i < count; i++) {
    const forcedAI = mode === "ai" && i > 0;
    const forcedHuman = mode === "local" || (mode === "ai" && i === 0);
    const defaultType = forcedAI ? "ai" : "human";

    const div = document.createElement("div");
    div.className = `player-row ${defaultType === "ai" ? "ai-row" : ""}`;

    const title = allowsPerPlayerType
      ? `Participant ${i + 1}`
      : (forcedAI ? `IA ${i}` : `Joueur ${i + 1}`);

    div.innerHTML = `
      <strong>${escapeHtml(title)} ${defaultType === "ai" ? '<span class="ai-badge constructive">IA anti-stagnation</span>' : '<span class="type-badge human-badge">Humain</span>'}</strong>

      ${allowsPerPlayerType ? `
      <label class="field">
        <span>Type de participant</span>
        <select id="playerType${i}">
          <option value="human" ${defaultType === "human" ? "selected" : ""}>Humain</option>
          <option value="ai" ${defaultType === "ai" ? "selected" : ""}>IA anti-stagnation</option>
        </select>
      </label>` : `<input type="hidden" id="playerType${i}" value="${defaultType}" />`}

      <label class="field">
        <span>Nom</span>
        <input id="playerName${i}" value="${escapeHtml(defaultType === "ai" ? `IA ${i}` : `Joueur ${i + 1}`)}" maxlength="24" ${forcedAI ? "readonly" : ""} />
      </label>
      <label class="field">
        <span>Couleur</span>
        <select id="playerColor${i}">
          ${COLOR_KEYS.map(c => `<option value="${c}">${COLORS[c].label}</option>`).join("")}
        </select>
      </label>
    `;
    els.playerInputs.appendChild(div);
  }

  const colorSelects = [...document.querySelectorAll('[id^="playerColor"]')];
  colorSelects.forEach((select, idx) => {
    select.value = COLOR_KEYS[idx];
    select.addEventListener("change", preventDuplicateColors);
  });

  const typeSelects = [...document.querySelectorAll('[id^="playerType"]')];
  typeSelects.forEach((select, idx) => {
    select.addEventListener("change", () => updateParticipantNameAndBadges(idx));
  });

  preventDuplicateColors();
}

function updateParticipantNameAndBadges(index) {
  const mode = els.gameMode?.value || "local";
  if (mode !== "mixed" && mode !== "tournament") return;

  const type = document.getElementById(`playerType${index}`)?.value || "human";
  const nameInput = document.getElementById(`playerName${index}`);

  if (nameInput) {
    const current = nameInput.value.trim();
    const looksAuto = current === `Joueur ${index + 1}` || current === `IA ${index + 1}` || current === `IA ${index}`;
    if (looksAuto || !current) {
      nameInput.value = type === "ai" ? `IA ${index + 1}` : `Joueur ${index + 1}`;
    }
    nameInput.readOnly = false;
  }

  renderPlayerInputsPreserveValues();
}

function renderPlayerInputsPreserveValues() {
  const mode = els.gameMode?.value || "local";
  if (mode !== "mixed" && mode !== "tournament") return;

  const count = Number(els.playerCount.value);
  const previous = [];

  for (let i = 0; i < count; i++) {
    previous.push({
      type: document.getElementById(`playerType${i}`)?.value || "human",
      name: document.getElementById(`playerName${i}`)?.value || `Joueur ${i + 1}`,
      color: document.getElementById(`playerColor${i}`)?.value || COLOR_KEYS[i],
    });
  }

  els.playerInputs.innerHTML = "";

  for (let i = 0; i < count; i++) {
    const data = previous[i];
    const isAI = data.type === "ai";
    const div = document.createElement("div");
    div.className = `player-row ${isAI ? "ai-row" : ""}`;
    div.innerHTML = `
      <strong>Participant ${i + 1} ${isAI ? '<span class="ai-badge constructive">IA anti-stagnation</span>' : '<span class="type-badge human-badge">Humain</span>'}</strong>

      <label class="field">
        <span>Type de participant</span>
        <select id="playerType${i}">
          <option value="human" ${!isAI ? "selected" : ""}>Humain</option>
          <option value="ai" ${isAI ? "selected" : ""}>IA anti-stagnation</option>
        </select>
      </label>

      <label class="field">
        <span>Nom</span>
        <input id="playerName${i}" value="${escapeHtml(data.name)}" maxlength="24" />
      </label>

      <label class="field">
        <span>Couleur</span>
        <select id="playerColor${i}">
          ${COLOR_KEYS.map(c => `<option value="${c}" ${data.color === c ? "selected" : ""}>${COLORS[c].label}</option>`).join("")}
        </select>
      </label>
    `;
    els.playerInputs.appendChild(div);
  }

  [...document.querySelectorAll('[id^="playerColor"]')].forEach(select => {
    select.addEventListener("change", preventDuplicateColors);
  });
  [...document.querySelectorAll('[id^="playerType"]')].forEach((select, idx) => {
    select.addEventListener("change", () => updateParticipantNameAndBadges(idx));
  });
  preventDuplicateColors();
}

function preventDuplicateColors() {
  const selects = [...document.querySelectorAll('[id^="playerColor"]')];
  const selected = selects.map(s => s.value);

  selects.forEach(select => {
    [...select.options].forEach(option => {
      const count = selected.filter(v => v === option.value).length;
      option.disabled = count > 0 && select.value !== option.value;
    });
  });
}

function cellDistance(a, b) {
  const ca = CELL_CENTROIDS?.[a];
  const cb = CELL_CENTROIDS?.[b];
  if (!ca || !cb) return 999;
  return Math.hypot(ca.x - cb.x, ca.y - cb.y);
}

function chooseGatheringZoneForPlayer(player, pieces = state.pieces) {
  const ownPieces = pieces.filter(piece => piece.color === player.color);
  if (!ownPieces.length) return "3F";

  const blocked = new Set(
    pieces
      .filter(piece => piece.color !== player.color)
      .map(piece => piece.position)
  );

  let bestCell = ownPieces[0].position;
  let bestScore = Infinity;

  for (const cellId of CELL_IDS) {
    if (blocked.has(cellId)) continue;

    const averageDistance = ownPieces.reduce((sum, piece) => sum + cellDistance(piece.position, cellId), 0) / ownPieces.length;
    const adjacencyCapacity = (SIDE_ADJACENCY_MAP[cellId] || []).filter(neighbour => !blocked.has(neighbour)).length;
    const centerPenalty = cellDistance(cellId, "3F") * 0.22;
    const score = averageDistance + centerPenalty - adjacencyCapacity * 10;

    if (score < bestScore) {
      bestScore = score;
      bestCell = cellId;
    }
  }

  return bestCell;
}

function aiMovedPieceIds(player) {
  return new Set(
    state.moveHistory
      .filter(move =>
        !move.pass &&
        !move.system &&
        !move.simulation &&
        move.playerId === player.id &&
        move.pieceId
      )
      .map(move => move.pieceId)
  );
}

function ownPiecesForPlayer(player) {
  return state.pieces
    .filter(piece => piece.color === player.color)
    .sort((a, b) => a.id.localeCompare(b.id, undefined, { numeric: true }));
}

function isPieceAssembledWithOwnGroup(player, piece) {
  if (!piece) return false;
  return (SIDE_ADJACENCY_MAP[piece.position] || []).some(cellId => {
    const neighbour = pieceAt(cellId);
    return neighbour &&
      neighbour.color === player.color &&
      neighbour.id !== piece.id &&
      neighbour.face === piece.face;
  });
}



function nextRequiredAIPiece(player, moves) {
  if (!player?.isAI) return null;

  const pieces = ownPiecesForPlayer(player);
  if (!pieces.length) return null;

  const legalPieceIds = new Set(moves.map(move => move.piece.id));
  let cursor = state.aiRotationCursor?.[player.id] || 0;

  // V30 : l’IA parcourt les 7 pions à tour de rôle.
  // Un pion déjà assemblé avec un autre pion par le côté est considéré utile
  // et peut être sauté pour travailler le pion suivant.
  for (let offset = 0; offset < pieces.length; offset++) {
    const piece = pieces[(cursor + offset) % pieces.length];

    if (!legalPieceIds.has(piece.id)) continue;
    if (isPieceAssembledWithOwnGroup(player, piece)) continue;

    return piece;
  }

  // Si tous les pions disponibles sont déjà assemblés, on rend la main
  // à la stratégie globale V27.
  return null;
}

function advanceAIRotationAfterMove(player, pieceId) {
  if (!player?.isAI || !pieceId) return;

  const pieces = ownPiecesForPlayer(player);
  const index = pieces.findIndex(piece => piece.id === pieceId);
  if (index < 0) return;

  state.aiRotationCursor = state.aiRotationCursor || {};
  state.aiRotationCursor[player.id] = (index + 1) % pieces.length;
}

function ownFaceConnectedGroups(player) {
  const pieces = ownPiecesForPlayer(player);
  const pieceById = new Map(pieces.map(piece => [piece.id, piece]));
  const visited = new Set();
  const groups = [];

  for (const piece of pieces) {
    if (visited.has(piece.id)) continue;

    const stack = [piece];
    const group = [];
    visited.add(piece.id);

    while (stack.length) {
      const current = stack.pop();
      group.push(current);

      for (const cellId of SIDE_ADJACENCY_MAP[current.position] || []) {
        const neighbour = pieceAt(cellId);
        if (
          neighbour &&
          neighbour.color === player.color &&
          neighbour.face === current.face &&
          pieceById.has(neighbour.id) &&
          !visited.has(neighbour.id)
        ) {
          visited.add(neighbour.id);
          stack.push(neighbour);
        }
      }
    }

    groups.push(group);
  }

  return groups;
}

function groupCentroid(group) {
  if (!group?.length) return { x: 300, y: 300 };
  const points = group.map(piece => CELL_CENTROIDS[piece.position]).filter(Boolean);
  if (!points.length) return { x: 300, y: 300 };
  return {
    x: points.reduce((sum, p) => sum + p.x, 0) / points.length,
    y: points.reduce((sum, p) => sum + p.y, 0) / points.length,
  };
}

function distanceToPoint(cellId, point) {
  const c = CELL_CENTROIDS[cellId];
  if (!c || !point) return 999;
  return Math.hypot(c.x - point.x, c.y - point.y);
}

function centralGroupForAI(player) {
  const groups = ownFaceConnectedGroups(player);
  if (!groups.length) return null;

  const bestPattern = closestWinningPatternForPlayer(player, state.pieces);
  const targetCells = bestPattern?.pattern || [];
  const targetSet = new Set(targetCells);
  const targetCenter = targetCells.length
    ? groupCentroid(targetCells.map(position => ({ position })))
    : { x: 300, y: 300 };

  let best = null;
  let bestScore = -Infinity;

  for (const group of groups) {
    const centroid = groupCentroid(group);
    const sameFaceBonus = group.length * 850;
    const inPattern = group.filter(piece => targetSet.has(piece.position)).length;
    const adjacency = sideAdjacencyScore(group);
    const centerDistance = Math.hypot(centroid.x - targetCenter.x, centroid.y - targetCenter.y);

    const score =
      group.length * 1700 +
      sameFaceBonus +
      inPattern * 1200 +
      adjacency * 600 -
      centerDistance * 3;

    if (score > bestScore) {
      bestScore = score;
      best = { group, ids: new Set(group.map(piece => piece.id)), centroid, score };
    }
  }

  return best;
}

function secondaryPiecesInRotation(player, moves) {
  const central = centralGroupForAI(player);
  if (!central) return [];

  const legalPieceIds = new Set(moves.map(move => move.piece.id));

  // Tous les pions hors du groupe central entrent dans la même file :
  // pions isolés + pions appartenant à des groupements secondaires.
  return ownPiecesForPlayer(player)
    .filter(piece => legalPieceIds.has(piece.id))
    .filter(piece => !central.ids.has(piece.id));
}

function nextSecondaryPieceInRotation(player, moves) {
  const secondaryPieces = secondaryPiecesInRotation(player, moves);
  if (!secondaryPieces.length) return null;

  const pieces = ownPiecesForPlayer(player);
  let cursor = state.aiRotationCursor?.[player.id] || 0;

  // V33 : on parcourt la liste complète des 7 pions, mais on ne retient
  // que ceux qui sont hors regroupement central. Un pion isolé est donc traité
  // comme un groupe secondaire d’un seul pion.
  for (let offset = 0; offset < pieces.length; offset++) {
    const piece = pieces[(cursor + offset) % pieces.length];
    if (secondaryPieces.some(candidate => candidate.id === piece.id)) {
      return piece;
    }
  }

  return secondaryPieces[0] || null;
}

function secondaryPieceToConnect(player, moves) {
  const central = centralGroupForAI(player);
  if (!central) return null;

  const required = nextSecondaryPieceInRotation(player, moves);
  if (required) return required;

  // Si aucun pion secondaire n’est légalement jouable, retour à la stratégie globale.
  return null;
}



// V51 — Path Planner : navigation réelle des pions isolés autour des barrières.
function v51EntryCells(player, central) {
  const entries = new Set();
  for (const member of central?.group || []) {
    for (const cellId of SIDE_ADJACENCY_MAP[member.position] || []) {
      const occupant = pieceAt(cellId);
      if (!occupant) entries.add(cellId);
    }
  }
  return [...entries];
}

function v51CellTraversalCost(cellId, player, movingPiece) {
  const occupant = pieceAt(cellId);
  if (occupant && occupant.id !== movingPiece.id) return Infinity;
  let cost = 1;
  let enemyNeighbours = 0;
  let neutralNeighbours = 0;
  for (const neighbourId of SIDE_ADJACENCY_MAP[cellId] || []) {
    const neighbour = pieceAt(neighbourId);
    if (!neighbour || neighbour.id === movingPiece.id) continue;
    if (neighbour.isNeutral) neutralNeighbours++;
    else if (neighbour.color !== player.color) enemyNeighbours++;
  }
  cost += enemyNeighbours * 2.4 + neutralNeighbours * 0.8;
  if ((SYMMETRIC_MOVES[cellId] || []).filter(dest => !pieceAt(dest)).length <= 1) cost += 1.6;
  return cost;
}

function v51RoutePlan(player, piece, startCell, central) {
  const targets = new Set(v51EntryCells(player, central));
  if (!targets.size) return { cost: Infinity, path: [], alternatives: 0, barrier: 10 };
  if (targets.has(startCell)) return { cost: 0, path: [startCell], alternatives: 1, barrier: 0 };

  const distances = new Map([[startCell, 0]]);
  const previous = new Map();
  const queue = [{ cell: startCell, cost: 0 }];
  let reached = null;
  while (queue.length) {
    queue.sort((a,b) => a.cost-b.cost);
    const current = queue.shift();
    if (current.cost !== distances.get(current.cell)) continue;
    if (targets.has(current.cell)) { reached = current.cell; break; }
    for (const next of SYMMETRIC_MOVES[current.cell] || []) {
      const step = v51CellTraversalCost(next, player, piece);
      if (!Number.isFinite(step)) continue;
      const nextCost = current.cost + step;
      if (nextCost < (distances.get(next) ?? Infinity)) {
        distances.set(next, nextCost); previous.set(next, current.cell);
        queue.push({ cell: next, cost: nextCost });
      }
    }
  }
  if (!reached) return { cost: Infinity, path: [], alternatives: 0, barrier: 10 };
  const path=[]; let cursor=reached;
  while (cursor) { path.push(cursor); cursor=previous.get(cursor); }
  path.reverse();
  const alternatives=(SYMMETRIC_MOVES[startCell]||[]).filter(next => Number.isFinite(v51CellTraversalCost(next,player,piece))).length;
  const direct=Math.max(1, Math.min(...[...targets].map(t=>cellDistance(startCell,t)))/85);
  const barrier=Math.max(0, (distances.get(reached)||0)-direct);
  return { cost: distances.get(reached), path, alternatives, barrier, target: reached };
}

function v51FailedRoutePenalty(player, move) {
  const history=(state.moveHistory||[]).filter(m=>!m.pass&&!m.system&&m.playerId===player.id&&m.pieceId===move.piece.id).slice(-18);
  let penalty=0;
  for (let i=0;i<history.length;i++) {
    const old=history[i]; const age=history.length-i;
    if (old.to===move.to) penalty += Math.max(120, 900-age*35);
    if (old.from===move.to && old.to===move.piece.position) penalty += 1500;
  }
  return penalty;
}

function v51PathPlannerScore(player, move, central) {
  if (!central || central.ids.has(move.piece.id)) return 0;
  const before=v51RoutePlan(player, move.piece, move.piece.position, central);
  const originalPosition=move.piece.position;
  const originalFace=move.piece.face;
  move.piece.position=move.to;
  move.piece.face=move.piece.face === "RECTO" ? "VERSO" : "RECTO";
  const afterCentral=centralGroupForAI(player) || central;
  const after=v51RoutePlan(player, move.piece, move.to, afterCentral);
  move.piece.position=originalPosition; move.piece.face=originalFace;

  const beforeCost=Number.isFinite(before.cost)?before.cost:60;
  const afterCost=Number.isFinite(after.cost)?after.cost:60;
  const routeProgress=(beforeCost-afterCost)*1150;
  const viableBonus=Number.isFinite(after.cost)?1100:-9000;
  const detourBonus=Math.max(0,after.alternatives-1)*260;
  const barrierEscape=Math.max(0,before.barrier-after.barrier)*620;
  const followsPath=before.path?.[1]===move.to ? 2600 : 0;
  return routeProgress+viableBonus+detourBonus+barrierEscape+followsPath-v51FailedRoutePenalty(player,move);
}


function centralConnectionScore(player, move) {
  const central = centralGroupForAI(player);
  if (!central) return 0;

  const centralPositions = central.group.map(piece => piece.position);

  const minDistanceToCentral = cellId => {
    if (!centralPositions.length) return distanceToPoint(cellId, central.centroid);
    return Math.min(...centralPositions.map(position => cellDistance(cellId, position)));
  };

  const beforeDistance = minDistanceToCentral(move.piece.position);
  const beforeCentroidDistance = distanceToPoint(move.piece.position, central.centroid);
  const beforeCentralSize = central.group.length;

  const undo = applyTemporaryMove(player, move.piece, move.to);
  const afterCentral = centralGroupForAI(player);
  const afterDistance = Math.min(
    ...(afterCentral?.group || central.group).map(piece => cellDistance(move.to, piece.position))
  );
  const afterCentroidDistance = distanceToPoint(move.to, afterCentral?.centroid || central.centroid);
  const sameFaceCentralNeighbours = (SIDE_ADJACENCY_MAP[move.to] || []).reduce((sum, cellId) => {
    const neighbour = pieceAt(cellId);
    return sum + (neighbour && neighbour.color === player.color && neighbour.face === move.piece.face ? 1 : 0);
  }, 0);
  const sizeGain = (afterCentral?.group?.length || 0) - beforeCentralSize;
  undoTemporaryMove(undo);

  const geometricScore = (
    (beforeDistance - afterDistance) * 18 +
    (beforeCentroidDistance - afterCentroidDistance) * 6 +
    sameFaceCentralNeighbours * 1800 +
    sizeGain * 2600
  );
  return geometricScore + v51PathPlannerScore(player, move, central);
}



function openingMovePool(player, moves) {
  if (!player?.isAI) return moves;

  const movedIds = aiMovedPieceIds(player);
  const targetDistinct = AI_OPENING_DISTINCT_PIECES;

  // Phase 1 : mobiliser les 7 pions différents en cherchant déjà le rapprochement.
  if (movedIds.size < targetDistinct) {
    const freshMoves = moves.filter(move => !movedIds.has(move.piece.id));
    const pool = freshMoves.length ? freshMoves : moves;

    return [...pool].sort((a, b) =>
      openingDevelopmentScore(player, b) + centralConnectionScore(player, b) -
      (openingDevelopmentScore(player, a) + centralConnectionScore(player, a))
    );
  }

  // Phase 2 : choisir un regroupement central et raccorder les groupes secondaires.
  // Exception : la défense immédiate reste autorisée dans chooseAIMove/minimax.
  const requiredPiece = secondaryPieceToConnect(player, moves);
  if (requiredPiece) {
    const forcedMoves = moves.filter(move => move.piece.id === requiredPiece.id);
    if (forcedMoves.length) {
      return [...forcedMoves].sort((a, b) =>
        openingDevelopmentScore(player, b) + centralConnectionScore(player, b) -
        (openingDevelopmentScore(player, a) + centralConnectionScore(player, a))
      );
    }
  }

  return moves;
}





function openingDevelopmentScore(player, move) {
  const beforePattern = winningPatternScore(player);
  const beforeZone = gatheringZoneScore(player);
  const beforePosition = evaluatePlayerPosition(player);

  const undo = applyTemporaryMove(player, move.piece, move.to);

  const afterPattern = winningPatternScore(player);
  const afterZone = gatheringZoneScore(player);
  const afterPosition = evaluatePlayerPosition(player);
  const repeated = recentBoardRepeatCount(boardSignature());

  let score = 0;
  score += (afterPattern - beforePattern) * 1.15;
  score += (afterZone - beforeZone) * 0.65;
  score += (afterPosition - beforePosition) * 0.55;
  score -= repeated * AI_STAGNATION_CONFIG.repeatedBoardPenalty;

  if (countImmediateWinningMoves(player) > 0) score += 180000;
  if (checkVictory(player)) score += AI_WIN_SCORE;

  undoTemporaryMove(undo);

  return score;
}



function gatheringZoneScore(player) {
  if (!player?.isAI) return 0;

  const zone = player.aiTargetZone || chooseGatheringZoneForPlayer(player, state.pieces);
  const pieces = state.pieces.filter(piece => piece.color === player.color);
  if (!pieces.length) return 0;

  const averageDistance = pieces.reduce((sum, piece) => sum + cellDistance(piece.position, zone), 0) / pieces.length;
  const closeCount = pieces.filter(piece => cellDistance(piece.position, zone) <= 155).length;
  const adjacentToZone = pieces.filter(piece => (SIDE_ADJACENCY_MAP[zone] || []).includes(piece.position)).length;

  return (
    -averageDistance * AI_ZONE_WEIGHTS.distance +
    closeCount * AI_ZONE_WEIGHTS.close +
    adjacentToZone * AI_ZONE_WEIGHTS.adjacent
  );
}


function audioContext() {
  const AudioContextClass = window.AudioContext || window.webkitAudioContext;
  if (!AudioContextClass) return null;
  if (!audioState.context) {
    audioState.context = new AudioContextClass();
    audioState.master = audioState.context.createGain();
    audioState.master.gain.value = 0.34;
    audioState.master.connect(audioState.context.destination);
    audioState.musicGain = audioState.context.createGain();
    audioState.musicGain.gain.value = 0.018;
    audioState.musicGain.connect(audioState.master);
  }
  return audioState.context;
}

function updateSoundButtons() {
  const label = audioState.enabled ? "🔊 Son" : "🔇 Son";
  for (const button of [els.soundToggle, els.soundToggleTop]) {
    if (!button) continue;
    button.textContent = label;
    button.setAttribute("aria-pressed", String(audioState.enabled));
    button.classList.toggle("sound-on", audioState.enabled);
  }
}

async function unlockMoveAudio() {
  if (!audioState.enabled) return;
  const ctx = audioContext();
  if (ctx?.state === "suspended") {
    try { await ctx.resume(); } catch {}
  }
  if (!audioState.moveAudio) {
    audioState.moveAudio = new Audio(audioState.moveSoundPath);
    audioState.moveAudio.preload = "auto";
    audioState.moveAudio.volume = audioState.moveVolume;
    try { audioState.moveAudio.load(); } catch {}
  }
}

async function toggleSound() {
  const ctx = audioContext();
  if (!ctx) return;
  if (ctx.state === "suspended") await ctx.resume();
  audioState.enabled = !audioState.enabled;
  updateSoundButtons();
  if (audioState.enabled) {
    if (!audioState.moveAudio) {
      audioState.moveAudio = new Audio(audioState.moveSoundPath);
      audioState.moveAudio.preload = "auto";
      audioState.moveAudio.volume = audioState.moveVolume;
    }
    startAmbientMusic();
    playWoodMoveSound(true);
  } else {
    stopAmbientMusic();
  }
}

function stopAmbientMusic() {
  if (audioState.musicTimer) {
    window.clearInterval(audioState.musicTimer);
    audioState.musicTimer = null;
  }
  for (const node of audioState.musicNodes) {
    try { node.stop?.(); } catch {}
    try { node.disconnect?.(); } catch {}
  }
  audioState.musicNodes = [];
}

function startAmbientMusic() {
  if (!audioState.enabled) return;
  const ctx = audioContext();
  if (!ctx) return;
  stopAmbientMusic();
  const notes = [196.00, 246.94, 293.66, 329.63, 392.00, 493.88];
  let step = 0;
  const playPadNote = () => {
    if (!audioState.enabled || !audioState.musicGain) return;
    const now = ctx.currentTime;
    const freq = notes[step % notes.length];
    step += 1;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    const filter = ctx.createBiquadFilter();
    osc.type = "sine";
    osc.frequency.setValueAtTime(freq, now);
    filter.type = "lowpass";
    filter.frequency.setValueAtTime(850, now);
    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(0.055, now + 0.45);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + 3.8);
    osc.connect(filter);
    filter.connect(gain);
    gain.connect(audioState.musicGain);
    osc.start(now);
    osc.stop(now + 4);
    audioState.musicNodes.push(osc, gain, filter);
    audioState.musicNodes = audioState.musicNodes.slice(-24);
  };
  playPadNote();
  audioState.musicTimer = window.setInterval(playPadNote, 2400);
}

function playWoodMoveSound(isActivation = false) {
  if (!audioState.enabled) return;

  // V25 : utiliser le fichier MP3 fourni pour le mouvement.
  // Le son est cloné à chaque coup pour permettre plusieurs sons rapprochés.
  try {
    if (!audioState.moveAudio) {
      audioState.moveAudio = new Audio(audioState.moveSoundPath);
      audioState.moveAudio.preload = "auto";
      audioState.moveAudio.volume = audioState.moveVolume;
    }

    const sound = audioState.moveAudio.cloneNode(true);
    sound.volume = isActivation ? Math.min(0.45, audioState.moveVolume) : audioState.moveVolume;
    sound.currentTime = 0;
    const playPromise = sound.play();
    if (playPromise?.catch) {
      playPromise.catch(() => playGeneratedMoveSound(isActivation));
    }
    return;
  } catch (error) {
    playGeneratedMoveSound(isActivation);
  }
}

function playGeneratedMoveSound(isActivation = false) {
  const ctx = audioContext();
  if (!ctx || !audioState.master) return;

  const now = ctx.currentTime;

  const bodyGain = ctx.createGain();
  const bodyFilter = ctx.createBiquadFilter();
  const bodyOsc = ctx.createOscillator();

  bodyOsc.type = "triangle";
  bodyOsc.frequency.setValueAtTime(isActivation ? 360 : 155 + Math.random() * 35, now);
  bodyOsc.frequency.exponentialRampToValueAtTime(isActivation ? 220 : 78, now + 0.16);

  bodyFilter.type = "bandpass";
  bodyFilter.frequency.setValueAtTime(isActivation ? 620 : 340, now);
  bodyFilter.Q.setValueAtTime(4.2, now);

  bodyGain.gain.setValueAtTime(0.0001, now);
  bodyGain.gain.exponentialRampToValueAtTime(isActivation ? 0.09 : 0.28, now + 0.008);
  bodyGain.gain.exponentialRampToValueAtTime(0.0001, now + 0.22);

  bodyOsc.connect(bodyFilter);
  bodyFilter.connect(bodyGain);
  bodyGain.connect(audioState.master);
  bodyOsc.start(now);
  bodyOsc.stop(now + 0.24);
}

function playVictorySound(onEnded = null) {
  const fallback = () => {
    playGeneratedVictorySound();
    if (typeof onEnded === "function") {
      window.setTimeout(onEnded, 1200);
    }
    return 1200;
  };

  if (!audioState.enabled) {
    if (typeof onEnded === "function") {
      window.setTimeout(onEnded, 900);
    }
    return 900;
  }

  try {
    if (!audioState.victoryAudio) {
      audioState.victoryAudio = new Audio(audioState.victorySoundPath);
      audioState.victoryAudio.preload = "auto";
      audioState.victoryAudio.volume = audioState.victoryVolume;
    }

    const sound = audioState.victoryAudio.cloneNode(true);
    sound.volume = audioState.victoryVolume;
    sound.currentTime = 0;

    let ended = false;
    const finish = () => {
      if (ended) return;
      ended = true;
      if (typeof onEnded === "function") onEnded();
    };

    sound.addEventListener("ended", finish, { once: true });

    const playPromise = sound.play();
    if (playPromise?.catch) {
      playPromise.catch(() => fallback());
    }

    const durationMs = Number.isFinite(sound.duration) && sound.duration > 0
      ? Math.ceil(sound.duration * 1000)
      : VICTORY_PAUSE_FALLBACK_MS;

    window.setTimeout(finish, durationMs + 180);
    return durationMs;
  } catch (error) {
    return fallback();
  }
}



function playGeneratedVictorySound() {
  const ctx = audioContext();
  if (!ctx || !audioState.master) return;

  const now = ctx.currentTime;
  const notes = [392, 523.25, 659.25, 783.99];

  notes.forEach((freq, index) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = "sine";
    osc.frequency.setValueAtTime(freq, now + index * 0.12);

    gain.gain.setValueAtTime(0.0001, now + index * 0.12);
    gain.gain.exponentialRampToValueAtTime(0.16, now + index * 0.12 + 0.03);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + index * 0.12 + 0.45);

    osc.connect(gain);
    gain.connect(audioState.master);

    osc.start(now + index * 0.12);
    osc.stop(now + index * 0.12 + 0.5);
  });
}



function closestWinningPatternForPlayer(player, pieces = state.pieces) {
  const ownPieces = pieces.filter(piece => piece.color === player.color);
  if (!ownPieces.length) return null;

  const occupiedByOthers = new Set(
    pieces
      .filter(piece => piece.color !== player.color)
      .map(piece => piece.position)
  );

  let best = null;
  let bestScore = -Infinity;

  for (let i = 0; i < WINNING_PATTERNS.length; i++) {
    const pattern = WINNING_PATTERNS[i];
    const patternSet = WINNING_PATTERN_CELL_SETS[i];

    let occupiedInPattern = 0;
    let blocked = 0;
    let distance = 0;

    for (const piece of ownPieces) {
      if (patternSet.has(piece.position)) {
        occupiedInPattern += 1;
        continue;
      }

      let nearest = Infinity;
      for (const cell of pattern) {
        nearest = Math.min(nearest, cellDistance(piece.position, cell));
      }
      distance += nearest;
    }

    for (const cell of pattern) {
      if (occupiedByOthers.has(cell)) blocked += 1;
    }

    const score =
      occupiedInPattern * AI_ZONE_WEIGHTS.winningPattern -
      distance * 0.55 -
      blocked * 2600 -
      (7 - occupiedInPattern) * AI_ZONE_WEIGHTS.missingPatternPenalty;

    if (score > bestScore) {
      bestScore = score;
      best = { pattern, score, occupiedInPattern, blocked };
    }
  }

  return best;
}

function winningPatternScore(player) {
  if (!player?.isAI) return 0;

  const best = closestWinningPatternForPlayer(player, state.pieces);
  if (!best) return 0;

  const faceCount = Math.max(
    state.pieces.filter(piece => piece.color === player.color && piece.face === "RECTO").length,
    state.pieces.filter(piece => piece.color === player.color && piece.face === "VERSO").length
  );

  return best.score + best.occupiedInPattern * best.occupiedInPattern * 420 + faceCount * 90;
}

function createPieces(players) {
  const controlledColors = new Set(players.map(p => p.color));
  const pieces = [];

  for (const color of COLOR_KEYS) {
    INITIAL_POSITIONS[color].forEach((position, index) => {
      pieces.push({
        id: `${color}-${index + 1}`,
        color,
        position,
        face: "VERSO",
        isNeutral: !controlledColors.has(color),
      });
    });
  }

  return pieces;
}

function startGame() {
  try {
  if (window.VR44Memory) VR44Memory.beginGame();
  clearAI();
  const mode = els.gameMode?.value || "local";
  const isTournament = mode === "tournament";
  const count = isTournament ? 4 : Number(els.playerCount.value);
  const players = [];

  for (let i = 0; i < count; i++) {
    const nameInput = document.getElementById(`playerName${i}`);
    const colorInput = document.getElementById(`playerColor${i}`);
    const typeInput = document.getElementById(`playerType${i}`);
    const isAI = (mode === "mixed" || isTournament) ? typeInput?.value === "ai" : (mode === "ai" && i > 0);
    const rawName = isAI ? (nameInput?.value || `IA ${i}`) : (nameInput?.value || `Joueur ${i + 1}`);
    const cleanedName = sanitizePlayerName(rawName);
    const name = cleanedName || (isAI ? `IA ${i}` : `Joueur ${i + 1}`);
    const color = colorInput?.value || COLOR_KEYS[i];
    players.push({ id: `P${i + 1}`, name, color, isAI });
  }

  if (new Set(players.map(p => p.color)).size !== players.length) {
    alert("Chaque joueur doit choisir une couleur différente.");
    return;
  }

  if (!players.some(p => !p.isAI)) {
    alert("Il faut au moins un joueur humain.");
    return;
  }

  stopTimer();

  const pieces = createPieces(players);
  const plannedPlayers = players.map(player => player.isAI
    ? { ...player, aiTargetZone: chooseGatheringZoneForPlayer(player, pieces) }
    : player
  );

  state = {
    status: "PLAYING",
    mode,
    players: plannedPlayers,
    pieces,
    turnOrder: shuffle(plannedPlayers.map(p => p.id)),
    currentTurnIndex: 0,
    selectedPieceId: null,
    legalDestinations: [],
    moveHistory: [],
    blockedInCycle: new Set(),
    ranking: [],
    winner: null,
    gameStartTime: Date.now(),
    aiPreview: null,
    aiPlans: Object.fromEntries(plannedPlayers.filter(p => p.isAI).map(p => [p.id, { targetZone: p.aiTargetZone }])),
    aiRotationCursor: Object.fromEntries(plannedPlayers.filter(p => p.isAI).map(p => [p.id, 0])),
    victoryPause: false,
    victoryPauseTimeout: null,
    tournament: isTournament ? {
      active: true,
      round: 1,
      originalPlayers: plannedPlayers.map(p => ({ id: p.id, name: p.name, color: p.color, isAI: p.isAI })),
      eliminationOrder: [],
      champion: null,
    } : null,
  };

  els.restartGame.disabled = false;
  els.resetSelection.disabled = false;

  startTimer();
  skipInactiveOrBlockedPlayersIfNeeded();
  render();
  updateExportButtons();
  if (els.engineStatus) els.engineStatus.textContent = `V53 active — ${WINNING_CONFIGURATION_COUNT.toLocaleString("fr-FR")} configurations gagnantes, Victory Planner profondeur ${AI_SEARCH_DEPTH_2_PLAYERS}.`;
  maybePlayAI();
  } catch (error) {
    console.error("Échec du lancement V53", error);
    setStatus("Impossible de lancer la partie : " + (error?.message || error));
    if (els.engineStatus) els.engineStatus.textContent = "Erreur moteur : " + (error?.message || error);
    alert("La partie n’a pas pu démarrer. Détail : " + (error?.message || error));
  }
}

function activePlayer() {
  if (state.status !== "PLAYING") return null;
  const id = state.turnOrder[state.currentTurnIndex];
  return state.players.find(p => p.id === id);
}

function pieceAt(cellId) {
  return state.pieces.find(p => p.position === cellId);
}

function rankingEntryForPlayer(playerId) {
  return state.ranking.find(entry => entry.playerId === playerId);
}

function rankingIndexForPlayer(playerId) {
  return state.ranking.findIndex(entry => entry.playerId === playerId);
}

function isPlayerRanked(playerId) {
  return rankingIndexForPlayer(playerId) >= 0;
}

function isMedaledPlayer(playerId) {
  const entry = rankingEntryForPlayer(playerId);
  return Boolean(entry && !entry.lastRemaining);
}

function medalForPlayer(playerId) {
  const index = rankingIndexForPlayer(playerId);
  const entry = rankingEntryForPlayer(playerId);
  if (index < 0 || !entry || entry.lastRemaining) return null;
  return MEDALS[index] || null;
}

function isPieceInactive(piece) {
  const owner = state.players.find(p => p.color === piece.color);
  return piece.isNeutral || (owner && isPlayerRanked(owner.id));
}

function isPieceMedaled(piece) {
  const owner = state.players.find(p => p.color === piece.color);
  return Boolean(owner && isMedaledPlayer(owner.id));
}

function activePlayers() {
  return state.players.filter(p => !isPlayerRanked(p.id));
}

function legalMovesForPiece(piece) {
  if (!piece || isPieceInactive(piece)) return [];
  return (SYMMETRIC_MOVES[piece.position] || [])
    .filter(dest => !pieceAt(dest))
    .filter(dest => !violatesRepetitionRule(piece, dest));
}

function ownerOfPiece(piece) {
  return state.players.find(player => player.color === piece.color);
}

function alternatingStreakLength(piece, to) {
  const owner = ownerOfPiece(piece);
  if (!owner) return 1;

  const pieceMoves = state.moveHistory.filter(move =>
    !move.pass &&
    !move.system &&
    move.playerId === owner.id &&
    move.pieceId === piece.id
  );

  let streak = 1;
  let from = piece.position;
  let dest = to;

  for (let i = pieceMoves.length - 1; i >= 0; i--) {
    const previous = pieceMoves[i];

    if (previous.from === dest && previous.to === from) {
      streak++;
      from = previous.from;
      dest = previous.to;
    } else {
      break;
    }
  }

  return streak;
}

function moveWinsImmediately(piece, to) {
  const owner = ownerOfPiece(piece);
  if (!owner) return false;
  const previousPosition = piece.position;
  const previousFace = piece.face;
  piece.position = to;
  piece.face = piece.face === "RECTO" ? "VERSO" : "RECTO";
  const wins = checkVictory(owner);
  piece.position = previousPosition;
  piece.face = previousFace;
  return wins;
}

function violatesRepetitionRule(piece, to) {
  const owner = ownerOfPiece(piece);
  const streak = alternatingStreakLength(piece, to);
  // V45 : l'IA est bloquée après deux aller-retour complets A↔B,
  // sauf si le prochain mouvement produit immédiatement une victoire.
  if (owner?.isAI && streak > 4) return !moveWinsImmediately(piece, to);
  return streak > MAX_BACK_AND_FORTH_STREAK;
}

function repetitionWarningForPiece(piece) {
  const legalIgnoringRepetition = (SYMMETRIC_MOVES[piece.position] || [])
    .filter(dest => !pieceAt(dest));

  const blockedByRule = legalIgnoringRepetition
    .filter(dest => violatesRepetitionRule(piece, dest));

  return blockedByRule.length > 0;
}

function legalMovesForPlayer(player) {
  if (!player || isPlayerRanked(player.id)) return [];
  return state.pieces
    .filter(p => p.color === player.color && !isPieceInactive(p))
    .flatMap(piece => legalMovesForPiece(piece).map(to => ({ piece, to })));
}

function selectPiece(pieceId) {
  if (state.status !== "PLAYING" || state.victoryPause) return;

  const player = activePlayer();
  if (player?.isAI) return;

  const piece = state.pieces.find(p => p.id === pieceId);

  if (!piece || isPieceInactive(piece) || !player || piece.color !== player.color) return;

  const moves = legalMovesForPiece(piece);

  if (moves.length === 0) {
    setStatus(repetitionWarningForPiece(piece) ? `${COLORS[piece.color].label} : coup interdit par la règle anti-répétition.` : `${COLORS[piece.color].label} : ce pion est bloqué.`);
    return;
  }

  state.selectedPieceId = pieceId;
  state.legalDestinations = moves;
  render();
}

function moveSelectedPiece(to) {
  if (state.status !== "PLAYING") return;
  if (!state.selectedPieceId || !state.legalDestinations.includes(to)) return;
  playMove(state.selectedPieceId, to);
}

function playMove(pieceId, to) {
  if (state.status !== "PLAYING") return;

  const player = activePlayer();
  const piece = state.pieces.find(p => p.id === pieceId);
  if (!player || !piece || piece.color !== player.color) return;

  const legal = legalMovesForPiece(piece);
  if (!legal.includes(to)) return;

  const from = piece.position;
  const previousFace = piece.face;
  const learningPiecesBefore = state.pieces.map(p => ({ id: p.id, color: p.color, position: p.position, face: p.face }));

  piece.position = to;
  piece.face = piece.face === "RECTO" ? "VERSO" : "RECTO";
  playWoodMoveSound();


  if (window.VR44Memory) {
    VR44Memory.recordMove({ piecesBefore: learningPiecesBefore, playerId: player.id, color: player.color, pieceId: piece.id, to, mode: state.mode || (player.isAI ? "ai" : "local"), ply: state.moveHistory.length });
  }

  state.moveHistory.push({
    playerId: player.id,
    playerName: player.name,
    color: player.color,
    pieceId: piece.id,
    from,
    to,
    previousFace,
    newFace: piece.face,
    afterSignature: boardSignature(),
    ai: player.isAI,
  });

  advanceAIRotationAfterMove(player, piece.id);

  state.selectedPieceId = null;
  state.legalDestinations = [];
  state.blockedInCycle.clear();

  if (checkVictory(player)) {
    registerPlayerVictory(player);
    if (state.status !== "PLAYING" || state.victoryPause) {
      render();
      return;
    }
  }

  nextTurn();
  skipInactiveOrBlockedPlayersIfNeeded();
  render();
  updateExportButtons();
  if (els.engineStatus && state.status === "PLAYING") els.engineStatus.textContent = `Dernier coup : ${player.name} ${from} → ${to}.`;
  maybePlayAI();
}

function pauseAfterVictory(message) {
  state.victoryPause = true;
  clearAI();
  setStatus(message);
  render();

  const resume = () => {
    if (state.status !== "PLAYING") return;

    state.victoryPause = false;
    state.victoryPauseTimeout = null;

    nextTurn();
    skipInactiveOrBlockedPlayersIfNeeded();
    render();
    maybePlayAI();
  };

  playVictorySound(resume);
}

function registerPlayerVictory(player) {
  if (isPlayerRanked(player.id)) return;

  const rankIndex = state.ranking.length;
  const medal = MEDALS[rankIndex];

  state.ranking.push({
    playerId: player.id,
    playerName: player.name,
    color: player.color,
    finishedAtMove: state.moveHistory.filter(move => !move.pass && !move.system).length,
    medal: medal?.label || null,
  });

  state.moveHistory.push({
    system: true,
    text: `${player.name} (${COLORS[player.color].label}) termine ${placeLabel(rankIndex)}${medal ? " — mode " + medal.label.toLowerCase() : ""}.`,
  });

  const remaining = activePlayers();

  if (state.players.length === 2) {
    playVictorySound();
    const last = remaining[0];
    if (last) addLastRemaining(last);
    finishGame(`Victoire de ${player.name} (${COLORS[player.color].label}) !`);
    return;
  }

  if (remaining.length === 1) {
    playVictorySound();
    addLastRemaining(remaining[0]);
    finishGame("Partie terminée : classement complet.");
    return;
  }

  pauseAfterVictory(`${player.name} termine ${placeLabel(rankIndex)}. Pause victoire…`);
}



function addLastRemaining(player) {
  if (!player || isPlayerRanked(player.id)) return;
  state.ranking.push({
    playerId: player.id,
    playerName: player.name,
    color: player.color,
    finishedAtMove: null,
    lastRemaining: true,
    medal: null,
  });
}

function finishGame(message) {
  if (window.VR44Memory) VR44Memory.finishGame({ ranking: state.ranking, players: state.players, draw: false });
  state.victoryPause = false;
  state.status = "FINISHED";
  state.winner = state.ranking[0] || null;
  state.selectedPieceId = null;
  state.legalDestinations = [];
  clearAI();
  stopTimer();
  setStatus(message);

  if (state.tournament && state.tournament.active && !state.tournament.champion) {
    advanceTournamentAfterRound();
  }
}

// --- Mode Tournoi -------------------------------------------------------------------------
// Un tournoi commence à 4 joueurs (humains ou IA). À la fin de chaque manche (le classement
// de la manche est alors complet), le joueur classé DERNIER de cette manche est éliminé
// (un seul éliminé par manche, quel que soit le nombre de joueurs encore en jeu à cet
// instant) : ses 7 pions repartent à leur case de départ mais restent figés et grisés
// (obstacles fixes, piece.isNeutral = true — même mécanisme que les couleurs non choisies
// en partie à 2/3 joueurs). SAUF s'il ne reste plus qu'un seul joueur : la manche était la
// finale, le tournoi est terminé, et le plateau final reste affiché tel quel (pas de remise
// à zéro puisqu'il n'y a pas de manche suivante).
// Si le tournoi continue, TOUS les pions (survivants comme déjà éliminés) reviennent à leur
// case de départ : chaque manche repart d'un plateau vierge, seuls les pions des éliminés
// (précédents et du jour) restent gelés sur leurs cases de départ. Un nouveau tirage au sort
// de l'ordre de jeu a lieu à chaque manche.
function advanceTournamentAfterRound() {
  const tournament = state.tournament;
  if (!tournament || tournament.champion) return;

  const ranking = state.ranking || [];
  const lastEntry = ranking[ranking.length - 1];
  const eliminatedPlayer = lastEntry ? state.players.find(p => p.id === lastEntry.playerId) : null;

  if (eliminatedPlayer) {
    state.pieces.forEach(piece => {
      if (piece.color === eliminatedPlayer.color) piece.isNeutral = true;
    });

    tournament.eliminationOrder.push({
      playerId: eliminatedPlayer.id,
      playerName: eliminatedPlayer.name,
      color: eliminatedPlayer.color,
      round: tournament.round,
      place: state.players.length,
    });

    state.players = state.players.filter(p => p.id !== eliminatedPlayer.id);
    if (state.aiPlans) delete state.aiPlans[eliminatedPlayer.id];
    if (state.aiRotationCursor) delete state.aiRotationCursor[eliminatedPlayer.id];

    state.moveHistory.unshift({
      system: true,
      text: `Tournoi — Manche ${tournament.round} : ${eliminatedPlayer.name} (${COLORS[eliminatedPlayer.color].label}) est éliminé. Ses pions restent figés sur le plateau.`,
    });
  }

  if (state.players.length <= 1) {
    const championPlayer = state.players[0] || null;
    tournament.champion = championPlayer ? {
      playerId: championPlayer.id,
      playerName: championPlayer.name,
      color: championPlayer.color,
    } : null;

    // Le joueur retiré (éliminé à l'instant) peut encore figurer dans turnOrder : on le
    // nettoie pour ne conserver que le champion, sinon renderGameInfo() plante en cherchant
    // un joueur qui n'existe plus dans state.players.
    state.turnOrder = championPlayer ? [championPlayer.id] : [];
    state.currentTurnIndex = 0;

    if (championPlayer) {
      state.moveHistory.unshift({
        system: true,
        text: `🏆 ${championPlayer.name} (${COLORS[championPlayer.color].label}) remporte le tournoi !`,
      });
      setStatus(`🏆 Tournoi remporté par ${championPlayer.name} !`);
    } else {
      setStatus("Tournoi terminé.");
    }

    render();
    return;
  }

  tournament.round += 1;
  state.status = "PLAYING";
  state.winner = null;
  state.ranking = [];
  state.selectedPieceId = null;
  state.legalDestinations = [];
  state.blockedInCycle = new Set();
  // Nouvelle manche = plateau remis à zéro : tous les pions (y compris ceux des joueurs
  // déjà éliminés lors de manches précédentes) reviennent à leur case de départ.
  // createPieces() gèle automatiquement (isNeutral = true) les couleurs qui ne sont plus
  // dans state.players, donc l'éliminé du jour comme les éliminés précédents restent bien
  // figés-et-grisés sur leur case de départ, pendant que les survivants repartent à zéro.
  state.pieces = createPieces(state.players);
  state.turnOrder = shuffle(state.players.map(p => p.id));
  state.currentTurnIndex = 0;
  state.gameStartTime = Date.now();
  state.victoryPause = false;
  state.victoryPauseTimeout = null;

  startTimer();
  skipInactiveOrBlockedPlayersIfNeeded();
  render();
  setStatus(`Tournoi — Manche ${tournament.round} : à vous de jouer (${state.players.length} joueurs restants).`);
  maybePlayAI();
}

function nextTurn() {
  if (!state.turnOrder.length) return;
  state.currentTurnIndex = (state.currentTurnIndex + 1) % state.turnOrder.length;
}

function skipInactiveOrBlockedPlayersIfNeeded() {
  if (state.status !== "PLAYING") return;

  let guard = 0;
  const maxGuard = Math.max(1, state.turnOrder.length * 2);

  while (guard < maxGuard) {
    const player = activePlayer();

    if (!player || isPlayerRanked(player.id)) {
      nextTurn();
      guard++;
      continue;
    }

    if (legalMovesForPlayer(player).length > 0) {
      setStatus(`${player.isAI ? "L’IA anti-stagnation réfléchit" : "À " + player.name + " de jouer"}.`);
      return;
    }

    state.blockedInCycle.add(player.id);
    state.moveHistory.push({
      playerId: player.id,
      playerName: player.name,
      color: player.color,
      pass: true,
    });

    const remaining = activePlayers();

    if (remaining.length <= 1) {
      if (remaining.length === 1) addLastRemaining(remaining[0]);
      finishGame("Partie terminée.");
      return;
    }

    if (remaining.every(p => state.blockedInCycle.has(p.id))) {
      if (state.ranking.length === 0) {
        if (state.tournament && state.tournament.active && !state.tournament.champion) {
          // Cas limite très rare : tous les joueurs actifs sont bloqués dès le début de la
          // manche, avant qu'aucun classement n'ait pu s'établir. Plutôt que de laisser le
          // tournoi bloqué indéfiniment en partie nulle, on élimine arbitrairement le
          // dernier joueur de l'ordre de jeu de cette manche (départage neutre) et le
          // tournoi continue normalement.
          const tieBreakLoserId = state.turnOrder[state.turnOrder.length - 1];
          state.ranking = remaining
            .slice()
            .sort((a, b) => (a.id === tieBreakLoserId ? 1 : b.id === tieBreakLoserId ? -1 : 0))
            .map(p => ({ playerId: p.id, playerName: p.name, color: p.color, finishedAtMove: null, lastRemaining: true, medal: null }));
          finishGame("Manche nulle (tous les joueurs bloqués) : départage neutre appliqué.");
        } else {
          state.status = "DRAW";
          clearAI();
          stopTimer();
          setStatus("Partie nulle : tous les joueurs sont bloqués.");
        }
      } else {
        finishGame("Partie terminée : les joueurs restants sont bloqués.");
      }
      return;
    }

    nextTurn();
    guard++;
  }
}

function maybePlayAI() {
  clearAI();
  if (state.status !== "PLAYING" || state.victoryPause) return;

  const player = activePlayer();
  if (!player?.isAI) return;

  state.selectedPieceId = null;
  state.legalDestinations = [];
  state.aiPreview = null;
  if (els.engineStatus) els.engineStatus.textContent = `${player.name} analyse les menaces et les trajectoires gagnantes…`;
  render();

  aiTimeout = window.setTimeout(() => {
    requestAIMove(player);
  }, AI_THINK_DELAY_MS);
}


function buildAIPreviewChoice(move) {
  return move ? {
    pieceId: move.piece.id,
    to: move.to,
    destinations: legalMovesForPiece(move.piece),
  } : null;
}

function quickAIMove(player) {
  const moves = legalMovesForPlayer(player);
  if (!moves.length) return null;

  if (window.VR44Memory) {
    const learned = VR44Memory.bestMove(state.pieces, player.color, moves, 2);
    if (learned) {
      const remembered = moves.find(m => m.piece.id === learned.pieceId && m.to === learned.to);
      if (remembered) return remembered;
    }
  }

  const winningMove = moves.find(move => wouldWinAfterMove(player, move.piece, move.to));
  if (winningMove) return winningMove;

  const blockers = immediateBlockMoves(player, moves);
  const strategicMoves = blockers.length ? blockers : openingMovePool(player, moves);
  const start = performance.now();
  const softBudget = 350;
  const beforeScore = evaluatePlayerPosition(player);

  let bestMove = strategicMoves[0];
  let bestScore = -Infinity;

  for (const move of strategicMoves) {
    const undo = applyTemporaryMove(player, move.piece, move.to);

    let score = evaluatePlayerPosition(player);
    const progressDelta = score - beforeScore;

    if (checkVictory(player)) score += AI_WIN_SCORE;
    if (progressDelta < -80) score -= 260000 + Math.abs(progressDelta) * 35;

    const repeated = recentBoardRepeatCount(boardSignature());
    if (repeated > 0) score -= repeated * 650000;

    if (countImmediateWinningMoves(player) > 0) score += 180000;

    undoTemporaryMove(undo);

    score += centralConnectionScore(player, move);

    if (score > bestScore) {
      bestScore = score;
      bestMove = move;
    }

    if (performance.now() - start > softBudget) break;
  }

  return bestMove;
}





function requestAIMove(player) {
  if (state.status !== "PLAYING" || activePlayer()?.id !== player.id) return;

  const playFallback = () => {
    if (state.status !== "PLAYING" || activePlayer()?.id !== player.id) return;
    const fallbackChoice = buildAIPreviewChoice(quickAIMove(player));
    previewAIMove(player, fallbackChoice);
  };

  if (typeof Worker === "undefined") {
    playFallback();
    return;
  }

  let resolved = false;

  const resolveWithChoice = choice => {
    if (resolved) return;
    resolved = true;

    if (aiDecisionTimeout) {
      window.clearTimeout(aiDecisionTimeout);
      aiDecisionTimeout = null;
    }

    terminateAIWorker();

    if (state.status !== "PLAYING" || activePlayer()?.id !== player.id) return;
    previewAIMove(player, choice || buildAIPreviewChoice(quickAIMove(player)));
  };

  try {
    const blob = new Blob([AI_WORKER_CODE], { type: "application/javascript" });
    aiWorkerURL = URL.createObjectURL(blob);
    aiWorker = new Worker(aiWorkerURL);

    aiDecisionTimeout = window.setTimeout(() => {
      resolveWithChoice(buildAIPreviewChoice(quickAIMove(player)));
    }, AI_WORKER_DEADLINE_MS);

    aiWorker.onmessage = event => {
      const payload = event.data;
      resolveWithChoice(payload?.ok && payload.choice ? payload.choice : null);
    };

    aiWorker.onerror = () => {
      resolveWithChoice(null);
    };

    const legalForMemory = legalMovesForPlayer(player);
    const memoryPriors = window.VR50Memory
      ? VR50Memory.getPriors(state.pieces, player.color, legalForMemory)
      : {};

    aiWorker.postMessage({
      state: buildAIStateSnapshot(),
      playerId: player.id,
      memoryPriors,
      symmetricMoves: SYMMETRIC_MOVES,
      sideAdjacencyMap: SIDE_ADJACENCY_MAP,
      cellCentroids: CELL_CENTROIDS,
      config: {
        maxBackAndForthStreak: MAX_BACK_AND_FORTH_STREAK,
        depthTwoPlayers: AI_SEARCH_DEPTH_2_PLAYERS,
        depthMulti: AI_SEARCH_DEPTH_MULTI,
        candidateLimitTwoPlayers: AI_CANDIDATE_LIMIT_2_PLAYERS,
        candidateLimitMulti: AI_CANDIDATE_LIMIT_MULTI,
        tacticalDepthTwoPlayers: 7,
        tacticalCandidateLimitTwoPlayers: 18,
        criticalDepthTwoPlayers: 9,
        criticalCandidateLimitTwoPlayers: 26,
        tacticalDepthMulti: 4,
        tacticalCandidateLimitMulti: 11,
        criticalDepthMulti: 5,
        criticalCandidateLimitMulti: 16,
        winScore: AI_WIN_SCORE,
        weights: AI_CONSTRUCTION_WEIGHTS,
        stagnation: AI_STAGNATION_CONFIG,
        rankedCount: state.ranking.length,
        postWinnerDepth: AI_STAGNATION_CONFIG.postWinnerDepth,
        postWinnerCandidateLimit: AI_STAGNATION_CONFIG.postWinnerCandidateLimit,
        maxDecisionMs: AI_MAX_TURN_MS,
        quiescenceDepth: 1,
        winningConfigurationCount: WINNING_CONFIGURATION_COUNT,
        openingDistinctPieces: AI_OPENING_DISTINCT_PIECES,
        zoneWeights: AI_ZONE_WEIGHTS,
        winningPatterns: WINNING_PATTERNS,
      },
    });
  } catch (error) {
    resolveWithChoice(null);
  }
}



function buildAIStateSnapshot() {
  return {
    status: state.status,
    mode: state.mode,
    players: state.players.map(p => ({ ...p })),
    pieces: state.pieces.map(p => ({ ...p })),
    turnOrder: [...state.turnOrder],
    moveHistory: state.moveHistory.filter(move => !move.simulation).map(move => ({ ...move })),
    ranking: state.ranking.map(entry => ({ ...entry })),
    aiPlans: { ...(state.aiPlans || {}) },
    aiRotationCursor: { ...(state.aiRotationCursor || {}) },
  };
}

function previewAIMove(player, choice) {
  if (!choice) {
    skipInactiveOrBlockedPlayersIfNeeded();
    render();
    return;
  }

  const pieceId = choice.pieceId || choice.piece?.id;
  const piece = state.pieces.find(p => p.id === pieceId);

  if (!piece || state.status !== "PLAYING" || state.victoryPause || activePlayer()?.id !== player.id) return;

  const destinations = choice.destinations?.length ? choice.destinations : legalMovesForPiece(piece);

  state.aiPreview = { pieceId, destinations, chosenDestination: null, phase: "options" };
  render();

  const showChoice = window.setTimeout(() => {
    if (state.status !== "PLAYING" || state.victoryPause || activePlayer()?.id !== player.id) return;
    state.aiPreview = { pieceId, destinations, chosenDestination: choice.to, phase: "chosen" };
    render();
  }, AI_PREVIEW_OPTIONS_MS);

  const playChoice = window.setTimeout(() => {
    if (state.status !== "PLAYING" || state.victoryPause || activePlayer()?.id !== player.id) return;
    state.aiPreview = null;
    playMove(pieceId, choice.to);
  }, AI_PREVIEW_PLAY_MS);

  aiPreviewTimeouts.push(showChoice, playChoice);
}

function terminateAIWorker() {
  if (aiWorker) {
    aiWorker.terminate();
    aiWorker = null;
  }
  if (aiWorkerURL) {
    URL.revokeObjectURL(aiWorkerURL);
    aiWorkerURL = null;
  }
}

function clearAI() {
  if (aiTimeout) {
    window.clearTimeout(aiTimeout);
    aiTimeout = null;
  }
  if (aiDecisionTimeout) {
    window.clearTimeout(aiDecisionTimeout);
    aiDecisionTimeout = null;
  }
  for (const timeout of aiPreviewTimeouts) {
    window.clearTimeout(timeout);
  }
  aiPreviewTimeouts = [];
  terminateAIWorker();
  state.aiPreview = null;
}

function opponentImmediateThreatCount(player) {
  return state.players
    .filter(p => p.id !== player.id && !isPlayerRanked(p.id))
    .reduce((sum, opponent) => sum + countImmediateWinningMoves(opponent), 0);
}

function immediateBlockMoves(player, moves) {
  const beforeThreats = opponentImmediateThreatCount(player);
  if (beforeThreats <= 0) return [];

  return moves.filter(move => {
    const undo = applyTemporaryMove(player, move.piece, move.to);
    const afterThreats = opponentImmediateThreatCount(player);
    undoTemporaryMove(undo);
    return afterThreats < beforeThreats;
  });
}

function chooseAIMove(player) {
  const moves = legalMovesForPlayer(player);
  if (!moves.length) return null;

  // 1. Victoire immédiate.
  const winningMove = moves.find(move => wouldWinAfterMove(player, move.piece, move.to));
  if (winningMove) return winningMove;

  // 2. Blocage temporaire stratégique si un adversaire menace immédiatement.
  const blockers = immediateBlockMoves(player, moves);
  const strategicBase = blockers.length ? blockers : openingMovePool(player, moves);

  const depth = aiSearchDepth();
  const cache = new Map();
  const ordered = limitMovesForSearch(orderMovesForSearch(player, strategicBase, player));

  let bestMove = ordered[0];
  let bestScore = -Infinity;
  let alpha = -Infinity;
  const beta = Infinity;

  for (const move of ordered) {
    const undo = applyTemporaryMove(player, move.piece, move.to);
    const score = minimax(nextSearchPlayer(player), depth - 1, alpha, beta, player, cache);
    undoTemporaryMove(undo);

    const tieBreak =
      staticMoveScore(player, move.piece, move.to, player) +
      centralConnectionScore(player, move);

    const bestTieBreak =
      staticMoveScore(player, bestMove.piece, bestMove.to, player) +
      centralConnectionScore(player, bestMove);

    if (score > bestScore || (score === bestScore && tieBreak > bestTieBreak)) {
      bestScore = score;
      bestMove = move;
    }

    alpha = Math.max(alpha, bestScore);
  }

  return bestMove;
}





function aiSearchDepth() {
  if (state.ranking.length > 0) return AI_STAGNATION_CONFIG.postWinnerDepth;
  return activePlayers().length <= 2 ? AI_SEARCH_DEPTH_2_PLAYERS : AI_SEARCH_DEPTH_MULTI;
}



function aiCandidateLimit() {
  if (state.ranking.length > 0) return AI_STAGNATION_CONFIG.postWinnerCandidateLimit;
  return activePlayers().length <= 2 ? AI_CANDIDATE_LIMIT_2_PLAYERS : AI_CANDIDATE_LIMIT_MULTI;
}



function limitMovesForSearch(moves) {
  return moves.slice(0, aiCandidateLimit());
}

function minimax(playerToMove, depth, alpha, beta, aiPlayer, cache) {
  const cacheKey = boardHash(playerToMove, depth, aiPlayer);
  if (cache.has(cacheKey)) return cache.get(cacheKey);

  if (checkVictory(aiPlayer)) return AI_WIN_SCORE + depth;

  const opponents = state.players.filter(p => p.id !== aiPlayer.id && !isPlayerRanked(p.id));
  if (opponents.some(opponent => checkVictory(opponent))) return -AI_WIN_SCORE - depth;

  if (depth <= 0) {
    const value = evaluateBoardForAI(aiPlayer);
    cache.set(cacheKey, value);
    return value;
  }

  if (!playerToMove || isPlayerRanked(playerToMove.id)) {
    const value = minimax(nextSearchPlayer(playerToMove), depth - 1, alpha, beta, aiPlayer, cache);
    cache.set(cacheKey, value);
    return value;
  }

  const moves = legalMovesForPlayer(playerToMove);

  if (!moves.length) {
    const value = minimax(nextSearchPlayer(playerToMove), depth - 1, alpha, beta, aiPlayer, cache);
    cache.set(cacheKey, value);
    return value;
  }

  const ordered = limitMovesForSearch(orderMovesForSearch(playerToMove, moves, aiPlayer));
  const maximizing = playerToMove.id === aiPlayer.id;

  if (maximizing) {
    let value = -Infinity;

    for (const move of ordered) {
      const undo = applyTemporaryMove(playerToMove, move.piece, move.to);
      value = Math.max(value, minimax(nextSearchPlayer(playerToMove), depth - 1, alpha, beta, aiPlayer, cache));
      undoTemporaryMove(undo);

      alpha = Math.max(alpha, value);
      if (alpha >= beta) break;
    }

    cache.set(cacheKey, value);
    return value;
  }

  let value = Infinity;

  for (const move of ordered) {
    const undo = applyTemporaryMove(playerToMove, move.piece, move.to);
    value = Math.min(value, minimax(nextSearchPlayer(playerToMove), depth - 1, alpha, beta, aiPlayer, cache));
    undoTemporaryMove(undo);

    beta = Math.min(beta, value);
    if (alpha >= beta) break;
  }

  cache.set(cacheKey, value);
  return value;
}

function boardHash(playerToMove, depth, aiPlayer) {
  const pieces = state.pieces
    .map(p => `${p.id}:${p.position}:${p.face}`)
    .sort()
    .join("|");

  const lastMoves = state.moveHistory
    .filter(move => !move.pass && !move.system)
    .slice(-10)
    .map(move => `${move.playerId}:${move.pieceId}:${move.from}>${move.to}`)
    .join(",");

  return `${aiPlayer.id}|${playerToMove?.id || "none"}|${depth}|${pieces}|${lastMoves}`;
}

function nextSearchPlayer(currentPlayer) {
  const players = state.players.filter(p => !isPlayerRanked(p.id));
  if (!players.length) return null;
  if (!currentPlayer) return players[0];

  const index = players.findIndex(p => p.id === currentPlayer.id);
  if (index < 0) return players[0];

  return players[(index + 1) % players.length];
}

function orderMovesForSearch(player, moves, aiPlayer) {
  const ordered = [...moves].sort((a, b) => {
    const scoreA = staticMoveScore(player, a.piece, a.to, aiPlayer);
    const scoreB = staticMoveScore(player, b.piece, b.to, aiPlayer);

    // Pour l'IA elle-même : meilleurs scores d'abord.
    // Pour un adversaire simulé : coups les plus dangereux pour l'IA d'abord.
    return player.id === aiPlayer.id ? scoreB - scoreA : scoreA - scoreB;
  });

  return ordered;
}



function applyTemporaryMove(player, piece, to) {
  const undo = {
    piece,
    previousPosition: piece.position,
    previousFace: piece.face,
  };

  const previousFace = piece.face;
  const from = piece.position;

  piece.position = to;
  piece.face = piece.face === "RECTO" ? "VERSO" : "RECTO";

  state.moveHistory.push({
    playerId: player.id,
    playerName: player.name,
    color: player.color,
    pieceId: piece.id,
    from,
    to,
    previousFace,
    newFace: piece.face,
    afterSignature: boardSignature(),
    simulation: true,
  });

  return undo;
}

function undoTemporaryMove(undo) {
  state.moveHistory.pop();
  undo.piece.position = undo.previousPosition;
  undo.piece.face = undo.previousFace;
}

function boardSignature() {
  return state.pieces
    .map(piece => `${piece.id}:${piece.position}:${piece.face}`)
    .sort()
    .join("|");
}

function recentBoardRepeatCount(signature) {
  const recentMoves = state.moveHistory
    .filter(move => !move.pass && !move.system && !move.simulation && move.afterSignature)
    .slice(-AI_STAGNATION_CONFIG.recentBoardLookback);

  return recentMoves.filter(move => move.afterSignature === signature).length;
}

function isImmediateReturn(piece, to) {
  const owner = ownerOfPiece(piece);
  if (!owner) return false;

  const lastMove = [...state.moveHistory]
    .reverse()
    .find(move =>
      !move.pass &&
      !move.system &&
      !move.simulation &&
      move.playerId === owner.id &&
      move.pieceId === piece.id
    );

  return Boolean(lastMove && lastMove.from === to && lastMove.to === piece.position);
}

function staticMoveScore(player, piece, to, aiPlayer) {
  const beforeConstructiveScore = evaluatePlayerPosition(player);

  const undo = applyTemporaryMove(player, piece, to);
  let score = evaluateBoardForAI(aiPlayer);

  const afterConstructiveScore = evaluatePlayerPosition(player);
  const progressDelta = afterConstructiveScore - beforeConstructiveScore;
  const repeatedBoards = recentBoardRepeatCount(boardSignature());
  const playerCreatesThreat = countImmediateWinningMoves(player);
  const winsNow = checkVictory(player);

  if (checkVictory(aiPlayer)) score += AI_WIN_SCORE;

  const opponents = state.players.filter(p => p.id !== aiPlayer.id && !isPlayerRanked(p.id));
  const immediateThreats = opponents.reduce((sum, opponent) => sum + countImmediateWinningMoves(opponent), 0);
  score -= immediateThreats * AI_CONSTRUCTION_WEIGHTS.dangerPenalty;

  // V15 : le retour immédiat du même pion est autorisé.
  // L’anti-stagnation ne vise plus que les boucles, les régressions
  // et les coups qui n’apportent aucun progrès utile.
  if (!winsNow) {
    if (repeatedBoards > 0) {
      score -= repeatedBoards * AI_STAGNATION_CONFIG.repeatedBoardPenalty;
    }

    if (progressDelta < -80) {
      score -= AI_STAGNATION_CONFIG.regressionPenalty + Math.abs(progressDelta) * AI_STAGNATION_CONFIG.regressionMultiplier;
    } else if (progressDelta < 20 && playerCreatesThreat === 0 && immediateThreats === 0) {
      score -= AI_STAGNATION_CONFIG.noProgressPenalty;
    }
  }

  undoTemporaryMove(undo);
  return score;
}





function evaluateBoardForAI(aiPlayer) {
  const opponents = state.players.filter(p => p.id !== aiPlayer.id && !isPlayerRanked(p.id));

  // La construction personnelle passe d’abord.
  let score = evaluatePlayerPosition(aiPlayer) * 1.65;

  // Défense raisonnée : on surveille les adversaires, mais on ne casse pas
  // automatiquement sa construction pour bloquer une menace faible.
  for (const opponent of opponents) {
    const threat = countImmediateWinningMoves(opponent);
    const opponentStrength = evaluatePlayerPosition(opponent);

    score -= opponentStrength * 0.45;
    score -= threat * AI_CONSTRUCTION_WEIGHTS.immediateThreatPenalty;
  }

  // Bonus si l’IA crée elle-même une menace gagnante.
  score += countImmediateWinningMoves(aiPlayer) * 420000;

  return score;
}

function evaluatePlayerPosition(player) {
  const pieces = state.pieces.filter(p => p.color === player.color);
  const groups = connectedGroupCount(pieces);
  const sameFaceCount = Math.max(
    pieces.filter(p => p.face === "RECTO").length,
    pieces.filter(p => p.face === "VERSO").length
  );
  const adjacency = sideAdjacencyScore(pieces);
  const compactness = averagePairDistance(pieces);
  const mobility = legalMovesForPlayer(player).length;
  const largestGroup = largestConnectedGroupSize(pieces);
  const centerControl = centerControlScore(pieces);

  let score = 0;

  // PRIORITÉ 1 : rapprocher les 7 pions.
  score += (10 - groups) * AI_CONSTRUCTION_WEIGHTS.groups;
  score += largestGroup * AI_CONSTRUCTION_WEIGHTS.largestGroup;
  score -= compactness * AI_CONSTRUCTION_WEIGHTS.compactness;

  // PRIORITÉ 2 : valoriser l’adjacence par les côtés.
  score += adjacency * AI_CONSTRUCTION_WEIGHTS.sideAdjacency;

  // PRIORITÉ 3 : mettre les pions sur la même face.
  score += sameFaceCount * AI_CONSTRUCTION_WEIGHTS.sameFace;

  // Bonus progressifs si la structure devient vraiment gagnante.
  if (groups === 1) score += 6200;
  if (largestGroup >= 5) score += 1800;
  if (largestGroup >= 6) score += 3200;

  if (sameFaceCount >= 5) score += 900;
  if (sameFaceCount >= 6) score += 2200;
  if (sameFaceCount === 7) score += 3600;

  // Critères secondaires : mobilité et centre.
  score += mobility * 7;
  score += centerControl * 18;

  // V22 : l’IA valorise les coups qui rapprochent ses pions
  // de sa zone de rassemblement choisie en début de partie.
  score += gatheringZoneScore(player);

  // V27 : rapprochement vers une combinaison gagnante réelle.
  score += winningPatternScore(player);

  return score;
}

function centerControlScore(pieces) {
  const center = { x: 300, y: 300 };
  return pieces.reduce((score, piece) => {
    const c = centroidOf(polygonForCell(piece.position));
    return score + Math.max(0, 350 - (Math.abs(c.x - center.x) + Math.abs(c.y - center.y)));
  }, 0) / 100;
}

function largestConnectedGroupSize(pieces) {
  const remaining = new Set(pieces.map(p => p.position));
  let largest = 0;

  while (remaining.size) {
    const start = remaining.values().next().value;
    const stack = [start];
    let size = 0;

    while (stack.length) {
      const current = stack.pop();
      if (!remaining.has(current)) continue;
      remaining.delete(current);
      size++;

      for (const neighbor of sideAdjacentCells(current)) {
        if (remaining.has(neighbor)) stack.push(neighbor);
      }
    }

    largest = Math.max(largest, size);
  }

  return largest;
}

function averagePairDistance(pieces) {
  if (pieces.length <= 1) return 0;

  let total = 0;
  let count = 0;

  for (let i = 0; i < pieces.length; i++) {
    for (let j = i + 1; j < pieces.length; j++) {
      const a = centroidOf(polygonForCell(pieces[i].position));
      const b = centroidOf(polygonForCell(pieces[j].position));
      total += Math.abs(a.x - b.x) + Math.abs(a.y - b.y);
      count++;
    }
  }

  return total / count;
}

function wouldWinAfterMove(player, piece, to) {
  const undo = applyTemporaryMove(player, piece, to);
  const result = checkVictory(player);
  undoTemporaryMove(undo);
  return result;
}

function countImmediateWinningMoves(player) {
  return legalMovesForPlayer(player)
    .filter(move => wouldWinAfterMove(player, move.piece, move.to))
    .length;
}

function connectedGroupCount(pieces) {
  const remaining = new Set(pieces.map(p => p.position));
  let groups = 0;

  while (remaining.size) {
    groups++;
    const start = remaining.values().next().value;
    const stack = [start];

    while (stack.length) {
      const current = stack.pop();
      if (!remaining.has(current)) continue;
      remaining.delete(current);

      for (const neighbor of sideAdjacentCells(current)) {
        if (remaining.has(neighbor)) stack.push(neighbor);
      }
    }
  }

  return groups;
}

function sideAdjacencyScore(pieces) {
  const positions = new Set(pieces.map(p => p.position));
  let score = 0;

  for (const piece of pieces) {
    for (const neighbor of sideAdjacentCells(piece.position)) {
      if (positions.has(neighbor)) score++;
    }
  }

  return score / 2;
}

function checkVictory(player) {
  const pieces = state.pieces.filter(p => p.color === player.color);
  if (pieces.length !== 7) return false;

  const firstFace = pieces[0].face;
  if (!pieces.every(p => p.face === firstFace)) return false;

  return areConnectedBySide(pieces);
}

function areConnectedBySide(pieces) {
  const positions = new Set(pieces.map(p => p.position));
  const start = pieces[0].position;
  const visited = new Set();
  const stack = [start];

  while (stack.length) {
    const current = stack.pop();

    if (visited.has(current)) continue;
    visited.add(current);

    for (const neighbor of sideAdjacentCells(current)) {
      if (positions.has(neighbor) && !visited.has(neighbor)) {
        stack.push(neighbor);
      }
    }
  }

  return visited.size === pieces.length;
}

function sideAdjacentCells(cellId) {
  return SIDE_ADJACENCY_MAP[cellId] || [];
}

function sharedVertices(a, b) {
  let count = 0;

  for (const p of a) {
    if (b.some(q => Math.abs(q.x - p.x) < 0.001 && Math.abs(q.y - p.y) < 0.001)) {
      count++;
    }
  }

  return count;
}

function setStatus(message) {
  els.gameStatus.textContent = message;
}

function formatDuration(ms) {
  const totalSeconds = Math.max(0, Math.floor(ms / 1000));
  const minutes = String(Math.floor(totalSeconds / 60)).padStart(2, "0");
  const seconds = String(totalSeconds % 60).padStart(2, "0");
  return `${minutes}:${seconds}`;
}

function updateTimerDisplay() {
  if (!els.gameTimer) return;

  if (!state.gameStartTime) {
    els.gameTimer.textContent = "00:00";
    return;
  }

  els.gameTimer.textContent = formatDuration(Date.now() - state.gameStartTime);
}

function startTimer() {
  stopTimer();
  updateTimerDisplay();
  timerInterval = window.setInterval(updateTimerDisplay, 1000);
}

function stopTimer() {
  if (timerInterval) {
    window.clearInterval(timerInterval);
    timerInterval = null;
  }
  updateTimerDisplay();
}

function resetSelection() {
  state.selectedPieceId = null;
  state.legalDestinations = [];
  render();
}

function restart() {
  if (!state.players.length && !state.tournament) return;

  stopTimer();
  clearAI();

  const isTournament = Boolean(state.tournament);
  // En mode tournoi, "Recommencer" relance TOUT le tournoi depuis les 4 joueurs d'origine
  // (y compris ceux déjà éliminés lors de la tentative précédente), pas seulement les
  // survivants actuels — sinon un tournoi interrompu ne pourrait plus jamais repartir à 4.
  const players = isTournament ? state.tournament.originalPlayers.map(p => ({ ...p })) : state.players;

  const pieces = createPieces(players);
  const plannedPlayers = players.map(player => player.isAI
    ? { ...player, aiTargetZone: chooseGatheringZoneForPlayer(player, pieces) }
    : player
  );

  state = {
    status: "PLAYING",
    mode: state.mode || "local",
    players: plannedPlayers,
    pieces,
    turnOrder: shuffle(plannedPlayers.map(p => p.id)),
    currentTurnIndex: 0,
    selectedPieceId: null,
    legalDestinations: [],
    moveHistory: [],
    blockedInCycle: new Set(),
    ranking: [],
    winner: null,
    gameStartTime: Date.now(),
    aiPreview: null,
    aiPlans: Object.fromEntries(plannedPlayers.filter(p => p.isAI).map(p => [p.id, { targetZone: p.aiTargetZone }])),
    aiRotationCursor: Object.fromEntries(plannedPlayers.filter(p => p.isAI).map(p => [p.id, 0])),
    victoryPause: false,
    victoryPauseTimeout: null,
    tournament: isTournament ? {
      active: true,
      round: 1,
      originalPlayers: plannedPlayers.map(p => ({ id: p.id, name: p.name, color: p.color, isAI: p.isAI })),
      eliminationOrder: [],
      champion: null,
    } : null,
  };

  startTimer();
  skipInactiveOrBlockedPlayersIfNeeded();
  render();
  maybePlayAI();
}

function squareDiag(squareCol, rowIndex) {
  const localC = squareCol % 2;
  const localR = rowIndex % 2;
  return localC === localR ? "/" : "\\";
}

function trianglePolygonsForSquare(squareCol, rowIndex) {
  const x = squareCol * 100;
  const y = rowIndex * 100;
  const w = 100;
  const h = 100;

  if (squareDiag(squareCol, rowIndex) === "/") {
    return [
      [{ x, y }, { x: x + w, y }, { x, y: y + h }],
      [{ x: x + w, y }, { x: x + w, y: y + h }, { x, y: y + h }],
    ];
  }

  return [
    [{ x, y }, { x: x + w, y }, { x: x + w, y: y + h }],
    [{ x, y }, { x, y: y + h }, { x: x + w, y: y + h }],
  ];
}

function buildCellPolygons() {
  const map = {};

  for (let r = 0; r < 6; r++) {
    const rowTriangles = [];

    for (let c = 0; c < 6; c++) {
      trianglePolygonsForSquare(c, r).forEach(poly => {
        rowTriangles.push({ poly, centroid: centroidOf(poly) });
      });
    }

    rowTriangles.sort((a, b) => a.centroid.x - b.centroid.x);

    rowTriangles.forEach((item, i) => {
      map[`${r + 1}${LETTERS[i]}`] = item.poly;
    });
  }

  return map;
}

const CELL_POLYGONS = buildCellPolygons();
const CELL_CENTROIDS = buildCellCentroids();
const SIDE_ADJACENCY_MAP = buildSideAdjacencyMap();

function buildCellCentroids() {
  const map = {};
  for (const cellId of CELL_IDS) {
    map[cellId] = centroidOf(CELL_POLYGONS[cellId]);
  }
  return map;
}

function buildSideAdjacencyMap() {
  const map = {};
  for (const cellId of CELL_IDS) {
    const poly = CELL_POLYGONS[cellId];
    map[cellId] = CELL_IDS.filter(other => {
      if (other === cellId) return false;
      return sharedVertices(poly, CELL_POLYGONS[other]) >= 2;
    });
  }
  return map;
}

function polygonForCell(cellId) {
  return CELL_POLYGONS[cellId];
}

function centroidOf(points) {
  return {
    x: points.reduce((sum, p) => sum + p.x, 0) / points.length,
    y: points.reduce((sum, p) => sum + p.y, 0) / points.length,
  };
}

function pointsToString(points) {
  return points.map(p => `${p.x},${p.y}`).join(" ");
}

function piecePolygon(cellId) {
  const poly = polygonForCell(cellId);
  const c = centroidOf(poly);

  return poly.map(p => ({
    x: c.x + (p.x - c.x) * 0.86,
    y: c.y + (p.y - c.y) * 0.86,
  }));
}

function renderBoard() {
  els.board.innerHTML = "";

  const selected = state.selectedPieceId ? state.pieces.find(p => p.id === state.selectedPieceId) : null;
  const selectedCell = selected?.position;

  for (const cellId of CELL_IDS) {
    const poly = polygonForCell(cellId);
    const cell = document.createElementNS("http://www.w3.org/2000/svg", "polygon");

    cell.setAttribute("points", pointsToString(poly));

    const preview = state.aiPreview;
    const isLegal = state.legalDestinations.includes(cellId);
    const isSelected = selectedCell === cellId;
    const isAIOption = Boolean(preview && !preview.chosenDestination && preview.destinations.includes(cellId));
    const isAIChosen = Boolean(preview && preview.chosenDestination === cellId);

    cell.setAttribute("class", `cell empty${isLegal ? " legal" : ""}${isSelected ? " selected" : ""}${isAIOption ? " ai-option" : ""}${isAIChosen ? " ai-chosen" : ""}`);

    if (isLegal && !state.aiPreview) {
      cell.addEventListener("click", () => moveSelectedPiece(cellId));
    }

    els.board.appendChild(cell);

    const c = centroidOf(poly);
    const label = document.createElementNS("http://www.w3.org/2000/svg", "text");

    label.setAttribute("x", c.x);
    label.setAttribute("y", c.y + 5);
    label.setAttribute("text-anchor", "middle");
    label.setAttribute("class", "cell-label");
    label.textContent = cellId;

    els.board.appendChild(label);
  }

  for (const piece of state.pieces) {
    const poly = piecePolygon(piece.position);
    const p = document.createElementNS("http://www.w3.org/2000/svg", "polygon");
    const owner = state.players.find(player => player.color === piece.color);
    const medal = owner ? medalForPlayer(owner.id) : null;
    const inactive = isPieceInactive(piece);
    const medaled = isPieceMedaled(piece);
    const fill = piece.isNeutral ? "#cfcfcf" : (medal ? medal.css : COLORS[piece.color].css);

    const aiFocused = state.aiPreview?.pieceId === piece.id;
    p.setAttribute("points", pointsToString(poly));
    p.setAttribute("fill", fill);
    p.setAttribute("class", `piece ${piece.isNeutral ? "neutral" : ""} ${medaled && medal ? medal.className : ""} ${inactive && !medaled && !piece.isNeutral ? "finished-piece" : "player-piece"}${aiFocused ? " ai-focused" : ""}`);

    if (!inactive) {
      p.addEventListener("click", () => selectPiece(piece.id));
    }

    els.board.appendChild(p);

    const c = centroidOf(poly);

    if (piece.face === "VERSO") {
      const dot = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      dot.setAttribute("cx", c.x);
      dot.setAttribute("cy", c.y);
      dot.setAttribute("r", 8);
      dot.setAttribute("class", "piece-dot");
      dot.setAttribute("fill", piece.isNeutral ? "#777" : (medal ? medal.dot : COLORS[piece.color].dot));
      dot.setAttribute("stroke", "#111");
      dot.setAttribute("stroke-width", "2");
      els.board.appendChild(dot);
    }

    const label = document.createElementNS("http://www.w3.org/2000/svg", "text");
    label.setAttribute("x", c.x);
    label.setAttribute("y", c.y + 24);
    label.setAttribute("text-anchor", "middle");
    label.setAttribute("class", `piece-label ${medaled ? "medal-label" : ""}`);
    label.setAttribute("fill", medaled ? "#2b241b" : (piece.color === "YELLOW" ? "#2b241b" : "#fff"));
    label.textContent = COLORS[piece.color].short;
    els.board.appendChild(label);
  }
}

function renderGameInfo() {
  const player = activePlayer();
  if (els.quitGame) els.quitGame.disabled = state.status === "SETUP";

  if (state.status === "SETUP") {
    setStatus("Configurez une partie");
  } else if (state.status === "PLAYING" && state.victoryPause) {
    setStatus("Pause victoire… reprise après la musique.");
  } else if (state.status === "PLAYING" && player) {
    if (player.isAI) {
      setStatus(`L’IA réfléchit — décision en 6 secondes maximum — ${legalMovesForPlayer(player).length} coup(s) possible(s).`);
    } else {
      setStatus(`À ${player.name} de jouer — ${legalMovesForPlayer(player).length} coup(s) possible(s).`);
    }
  } else if (state.status === "FINISHED") {
    setStatus(state.tournament?.champion
      ? `🏆 Tournoi remporté par ${state.tournament.champion.playerName} !`
      : "Partie terminée.");
  } else if (state.status === "DRAW") {
    setStatus("Partie nulle : tous les joueurs sont bloqués.");
  }

  const moveCount = state.moveHistory.filter(move => !move.pass && !move.system).length;
  if (els.moveCounter) els.moveCounter.textContent = String(moveCount);
  updateTimerDisplay();

  if (!state.players.length) {
    els.turnOrder.innerHTML = "Aucune partie lancée.";
    els.activePlayer.textContent = "—";
    if (els.moveCounter) els.moveCounter.textContent = "0";
    if (els.gameTimer) els.gameTimer.textContent = "00:00";
  } else {
    els.turnOrder.innerHTML = state.turnOrder.map((id, idx) => {
      const p = state.players.find(pl => pl.id === id);
      const active = state.status === "PLAYING" && idx === state.currentTurnIndex && !isPlayerRanked(p.id);
      const entry = rankingEntryForPlayer(p.id);
      const finished = Boolean(entry && !entry.lastRemaining);
      const lastRemaining = Boolean(entry && entry.lastRemaining);
      const rankIndex = rankingIndexForPlayer(p.id);
      const medal = finished ? MEDALS[rankIndex] : null;

      return `<div class="turn-pill ${active ? "active" : ""} ${active && p.isAI ? "ai-thinking" : ""} ${finished ? "finished" : ""}">
        ${medal ? medalDot(rankIndex) : colorDot(p.color)}
        <span>${escapeHtml(p.name)}${p.isAI ? " <span class='ai-badge'>IA</span>" : ""} — ${COLORS[p.color].label}${finished ? " — " + placeLabel(rankIndex) + " / " + medal.label : ""}${lastRemaining ? " — dernier joueur restant" : ""}</span>
      </div>`;
    }).join("");

    if (player && !isPlayerRanked(player.id)) {
      els.activePlayer.innerHTML = `${colorDot(player.color)} ${escapeHtml(player.name)}${player.isAI ? " <span class='ai-badge'>IA</span>" : ""} — ${COLORS[player.color].label}`;
    } else if (state.status === "FINISHED") {
      els.activePlayer.textContent = "Partie terminée";
    } else {
      els.activePlayer.textContent = "—";
    }
  }

  if (els.rankingList) {
    if (!state.ranking.length) {
      els.rankingList.innerHTML = `<li class="muted">Aucun classement pour l’instant.</li>`;
    } else {
      els.rankingList.innerHTML = state.ranking.map((entry, index) => {
        const suffix = entry.lastRemaining ? " — dernier joueur restant" : "";
        const medal = entry.lastRemaining ? "" : ` — ${entry.medal}`;
        return `<li><span class="ranking-place">${placeLabel(index)}</span> — ${entry.lastRemaining ? colorDot(entry.color) : medalDot(index)} ${escapeHtml(entry.playerName)} (${COLORS[entry.color].label})${medal}${suffix}</li>`;
      }).join("");
    }
  }

  els.moveHistory.innerHTML = state.moveHistory.map(move => {
    if (move.system) return `<li><strong>${escapeHtml(move.text)}</strong></li>`;
    if (move.pass) return `<li>${escapeHtml(move.playerName)} (${COLORS[move.color].label}) passe automatiquement : aucun coup légal.</li>`;
    return `<li>${move.ai ? "IA — " : ""}${escapeHtml(move.playerName)} : ${move.from} → ${move.to} <strong>${move.previousFace} → ${move.newFace}</strong></li>`;
  }).join("");

  els.resetSelection.disabled = state.status !== "PLAYING" || Boolean(activePlayer()?.isAI);
  els.restartGame.disabled = state.players.length === 0 && !state.tournament;
}

function render() {
  const gameView = state.status === "PLAYING" || state.status === "FINISHED" || state.status === "DRAW";
  document.body.classList.toggle("is-playing", gameView);
  document.body.classList.toggle("is-ended", state.status === "FINISHED" || state.status === "DRAW");
  renderBoard();
  renderGameInfo();
  renderTournamentPanel();
  saveGameToStorage();
}

function renderTournamentPanel() {
  if (!els.tournamentPanel) return;
  const tournament = state.tournament;

  if (!tournament) {
    els.tournamentPanel.hidden = true;
    return;
  }

  els.tournamentPanel.hidden = false;

  if (els.tournamentRound) {
    els.tournamentRound.textContent = tournament.champion
      ? `🏆 Champion : ${tournament.champion.playerName} (${COLORS[tournament.champion.color].label})`
      : `Manche ${tournament.round} — ${state.players.length} joueur(s) encore en lice sur ${tournament.originalPlayers.length}.`;
  }

  if (els.tournamentBracket) {
    const rows = [];

    if (tournament.champion) {
      rows.push(`<li class="tournament-champion">🏆 Champion — ${escapeHtml(tournament.champion.playerName)} (${COLORS[tournament.champion.color].label})</li>`);
    }

    // Éliminations affichées de la plus récente à la plus ancienne (ordre inverse
    // d'élimination = ordre du classement final : dernier éliminé remonte juste sous le
    // champion).
    [...tournament.eliminationOrder].reverse().forEach(entry => {
      rows.push(`<li>${placeLabel(entry.place - 1)} — ${escapeHtml(entry.playerName)} (${COLORS[entry.color].label}) — éliminé en manche ${entry.round}</li>`);
    });

    els.tournamentBracket.innerHTML = rows.join("") || '<li class="muted">Aucune élimination pour l’instant.</li>';
  }
}


function returnToSetup() {
  const confirmExit = state.status === "PLAYING"
    ? window.confirm("Annuler la partie en cours et revenir à la configuration ?")
    : true;

  if (!confirmExit) return;

  clearAI();
  stopTimer();
  clearSavedGame();
  state = emptyState();
  renderPlayerInputs();
  render();
}

els.gameMode?.addEventListener("change", renderPlayerInputs);
els.playerCount.addEventListener("change", renderPlayerInputs);

function updateExportButtons() {
  const enabled = Array.isArray(state.moveHistory) && state.moveHistory.length > 0;
  if (els.exportGameJson) els.exportGameJson.disabled = !enabled;
  if (els.exportGameCsv) els.exportGameCsv.disabled = !enabled;
}

function downloadTextFile(filename, content, mimeType) {
  const blob = new Blob([content], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  window.setTimeout(() => URL.revokeObjectURL(url), 0);
}

function exportCurrentGameJSON() {
  const payload = {
    schema: "verso-recto-game-v53",
    exportedAt: new Date().toISOString(),
    winningConfigurationCount: WINNING_CONFIGURATION_COUNT,
    status: state.status, mode: state.mode, players: state.players, ranking: state.ranking,
    moveHistory: state.moveHistory.filter(move => !move.simulation),
    finalPieces: state.pieces.map(piece => ({ id: piece.id, color: piece.color, position: piece.position, face: piece.face })),
  };
  downloadTextFile(`verso-recto-v53-${Date.now()}.json`, JSON.stringify(payload, null, 2), "application/json");
}

function csvCell(value) {
  let text = value == null ? "" : String(value);
  // Protection contre l'injection de formule CSV (Excel/LibreOffice) : si la cellule
  // commence par un caractère interprétable comme le début d'une formule, on préfixe
  // d'une apostrophe pour forcer une lecture en texte brut.
  if (/^[=+\-@\t\r]/.test(text)) {
    text = `'${text}`;
  }
  return `"${text.replaceAll('"', '""')}"`;
}

function exportCurrentGameCSV() {
  const rows = [["tour","joueur","couleur","pion","depart","arrivee","face_avant","face_apres","ia","type"]];
  state.moveHistory.filter(move => !move.simulation).forEach((move, index) => {
    rows.push([index + 1, move.playerName || "", move.color || "", move.pieceId || "", move.from || "", move.to || "", move.previousFace || "", move.newFace || "", move.ai ? "oui" : "non", move.pass ? "passe" : move.system ? "systeme" : "coup"]);
  });
  downloadTextFile(`verso-recto-v53-${Date.now()}.csv`, rows.map(row => row.map(csvCell).join(";")).join("\n"), "text/csv;charset=utf-8");
}

window.addEventListener("error", event => {
  console.error("Erreur V53", event.error || event.message);
  if (els.engineStatus) els.engineStatus.textContent = `Erreur détectée : ${event.message}`;
});

els.startGame.addEventListener("click", startGame);
els.exportGameJson?.addEventListener("click", exportCurrentGameJSON);
els.exportGameCsv?.addEventListener("click", exportCurrentGameCSV);
els.resetSelection.addEventListener("click", resetSelection);
els.restartGame.addEventListener("click", restart);
els.quitGame?.addEventListener("click", returnToSetup);
els.newGameTop.addEventListener("click", returnToSetup);
els.soundToggle?.addEventListener("click", toggleSound);
els.soundToggleTop?.addEventListener("click", toggleSound);

// Les navigateurs mobiles exigent une interaction avant de lire un son.
// Le premier toucher/clic prépare le MP3 afin que chaque déplacement, humain ou IA, soit audible.
document.addEventListener("pointerdown", unlockMoveAudio, { once: true, passive: true });
document.addEventListener("keydown", unlockMoveAudio, { once: true });
els.startGame?.addEventListener("click", unlockMoveAudio);

renderPlayerInputs();
updateSoundButtons();

const restoredGame = loadGameFromStorage();
if (restoredGame) {
  state = restoredGame;
  els.restartGame.disabled = false;
  els.resetSelection.disabled = false;
  startTimer();
  render();
  updateExportButtons();
  maybePlayAI();
} else {
  render();
}
